import ADJSON

// Same shape as the hand-written `User`/`Profile`, but the fast-path conformance is
// generated by @JSONCodable — so the bench measures the macro-generated code directly.

@JSONCodable
struct MacroProfile: Codable, Equatable {
    var bio: String
    var company: String?
    var publicRepos: Int
    var location: String?
}

@JSONCodable
struct MacroUser: Codable, Equatable {
    var id: Int
    var login: String
    var name: String?
    var email: String?
    var followers: Int
    var following: Int
    var isAdmin: Bool
    var score: Double
    var tags: [String]
    var profile: MacroProfile
}
